import React from 'react';
import { motion } from 'framer-motion';
import { useTheme } from '../contexts/ThemeContext';
import './About.css';

const About = () => {
  const { isDarkMode } = useTheme();

  return (
    <section id="about" className={`about-section ${isDarkMode ? 'dark' : ''}`}>
      <div className="container">
        <motion.h2 
          className="section-title"
          initial={{ opacity: 0, y: -20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.6 }}
          viewport={{ once: true }}
        >
          About Me
        </motion.h2>
        <motion.div 
          className="about-content"
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2, duration: 0.8 }}
          viewport={{ once: true }}
        >
          <p>
            Passionate AWS Cloud Engineer with expertise in designing, implementing, and managing scalable cloud infrastructure. 
            Specialized in DevOps practices, automation, and cost optimization strategies. Committed to delivering robust, 
            secure, and efficient cloud solutions.
          </p>
        </motion.div>
      </div>
    </section>
  );
};

export default About;
